body.script:
//
					const slides = document.querySelectorAll('.slide');
					const ind = document.getElementById('ind');
					let cur = 0;

					function show(i) {
						slides[cur].classList.remove('active');
						cur = ((i % slides.length) + slides.length) % slides.length;
						const slide = slides[cur];
						const iframe = slide.querySelector('iframe');
						if (!iframe.dataset.loaded) {
							iframe.src = slide.dataset.src;
							iframe.dataset.loaded = '1';
						}
						slide.classList.add('active');
						ind.textContent = slide.dataset.label;
					}

					show(0);

					document.addEventListener('keydown', e => {
						if (e.key === 'ArrowRight') show(cur + 1);
						else if (e.key === 'ArrowLeft') show(cur - 1);
					});

					let touchX = null;
					const overlay = document.getElementById('swipe-overlay');
					overlay.addEventListener('touchstart', e => {
						touchX = e.touches[0].clientX;
					}, { passive: true });
					overlay.addEventListener('touchend', e => {
						if (touchX === null) return;
						const dx = e.changedTouches[0].clientX - touchX;
						touchX = null;
						if (Math.abs(dx) < 40) return;
						show(dx < 0 ? cur + 1 : cur - 1);
					}, { passive: true });
				//

//
					const cfg              = document.getElementById('cfg').dataset;
					const INSTRUMENT       = cfg.instrument;
					const ASSET            = cfg.asset;
					const MONTHLY_INST     = cfg.monthly || '';
					const REFRESH          = parseInt(cfg.refresh, 10) * 1000;
					const DZ_URL           = '/api/delta-zero/' + INSTRUMENT;
					const MDZ_URL          = MONTHLY_INST ? '/api/delta-zero/' + MONTHLY_INST : '';
					const ADZ_URL          = '/api/delta-zero-all/' + ASSET;
					const DZT_URL          = '/api/delta-zero-tomorrow/' + ASSET;
					const DZT2_URL         = '/api/delta-zero-day-after-tomorrow/' + ASSET;
					const GL_W_URL         = '/api/gamma-levels/' + INSTRUMENT;
					const GL_M_URL         = MONTHLY_INST ? '/api/gamma-levels/' + MONTHLY_INST : '';
					const QG_URL           = '/api/quadrant-gamma/' + ASSET;
					const ZE_URL           = '/api/zones-extrema/' + ASSET;
					const ZB_URL           = '/api/zones-box/' + ASSET;
					const ZB_NEXT_URL      = '/api/zones-box-next/' + ASSET;
					const NEAREST_EXPIRY_URL = '/api/nearest-expiry/' + ASSET;
					let   INTERVAL         = '1h';
					const klineUrl   = (iv, limit) => '/api/klines/' + ASSET + '?interval=' + iv + '&limit=' + limit;

					const berlinOffset = (() => {
						const d = new Date();
						const utc = new Date(d.toLocaleString('en-US', { timeZone: 'UTC' }));
						const ber = new Date(d.toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));
						return (ber - utc) / 1000;
					})();

					const chart = LightweightCharts.createChart(document.getElementById('chart-container'), {
						width: window.innerWidth, height: window.innerHeight,
						layout: { background: { type: 'solid', color: '#ffffff' }, textColor: '#333333' },
						grid: { vertLines: { color: '#e8e8e8' }, horzLines: { color: '#e8e8e8' } },
						crosshair: { mode: LightweightCharts.CrosshairMode.Normal, horzLine: { labelBackgroundColor: 'blue' } },
						rightPriceScale: { borderColor: '#cccccc' },
						timeScale: { borderColor: '#cccccc', timeVisible: true, secondsVisible: false },
						localization: {
							timeFormatter: ts => new Date(ts * 1000).toLocaleString('de-DE', {
								timeZone: 'UTC',
								month: 'short', day: 'numeric',
								hour: '2-digit', minute: '2-digit',
							}),
						},
					});

					window.addEventListener('resize', () => chart.resize(window.innerWidth, window.innerHeight));

					const series = chart.addCandlestickSeries({
						upColor: '#26a69a', downColor: '#ef5350',
						borderVisible: false, wickUpColor: '#26a69a', wickDownColor: '#ef5350',
					});

					const netCallSeries = chart.addLineSeries({ priceScaleId: 'qg', color: '#1565c0', lineWidth: 2, title: 'Net Call Gamma' });
					const netPutSeries  = chart.addLineSeries({ priceScaleId: 'qg', color: '#e65100', lineWidth: 2, title: 'Net Put Gamma' });
					chart.priceScale('qg').applyOptions({ scaleMargins: { top: 0.8, bottom: 0 } });

					// Plain price levels (not dollar amounts), so these live on the
					// default/main price scale directly with the candles, not on the
					// 'qg' dollar-gamma scale.
					const topIntersectionSeries    = chart.addLineSeries({ color: '#2e7d32', lineWidth: 2, lastValueVisible: false, priceLineVisible: false });
					const bottomIntersectionSeries = chart.addLineSeries({ color: '#c62828', lineWidth: 2, lastValueVisible: false, priceLineVisible: false });

					// Zones boxes: filled rectangles marking the above-price and below-price
					// zero-crossing zones, using addBaselineSeries's flat top-line + baseValue
					// fill (the "line" is a constant top price, filled down to a constant
					// baseValue bottom price) to fake a bounded rectangle Lightweight Charts
					// has no native primitive for.
					const aboveBoxSeries = chart.addBaselineSeries({
						baseValue: { type: 'price', price: 0 },
						topLineColor: '#fbc02d', topFillColor1: 'rgba(251, 192, 45, 0.2)', topFillColor2: 'rgba(251, 192, 45, 0.2)',
						bottomLineColor: '#fbc02d', bottomFillColor1: 'rgba(251, 192, 45, 0.2)', bottomFillColor2: 'rgba(251, 192, 45, 0.2)',
						lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false,
					});
					const belowBoxSeries = chart.addBaselineSeries({
						baseValue: { type: 'price', price: 0 },
						topLineColor: '#fbc02d', topFillColor1: 'rgba(251, 192, 45, 0.2)', topFillColor2: 'rgba(251, 192, 45, 0.2)',
						bottomLineColor: '#fbc02d', bottomFillColor1: 'rgba(251, 192, 45, 0.2)', bottomFillColor2: 'rgba(251, 192, 45, 0.2)',
						lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false,
					});
					// addBaselineSeries only strokes its top edge; add a plain line series
					// for the bottom edge so both edges get the same visible border.
					const aboveBoxBottomLine = chart.addLineSeries({ color: '#fbc02d', lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false });
					const belowBoxBottomLine = chart.addLineSeries({ color: '#fbc02d', lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false });

					// Same mechanism as the boxes above, but for the next active expiry
					// after the nearest one — a distinct blue color so the two expiries'
					// boxes stay visually distinguishable when their price zones overlap.
					const aboveBoxSeriesNext = chart.addBaselineSeries({
						baseValue: { type: 'price', price: 0 },
						topLineColor: '#1e88e5', topFillColor1: 'rgba(30, 136, 229, 0.2)', topFillColor2: 'rgba(30, 136, 229, 0.2)',
						bottomLineColor: '#1e88e5', bottomFillColor1: 'rgba(30, 136, 229, 0.2)', bottomFillColor2: 'rgba(30, 136, 229, 0.2)',
						lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false,
					});
					const belowBoxSeriesNext = chart.addBaselineSeries({
						baseValue: { type: 'price', price: 0 },
						topLineColor: '#1e88e5', topFillColor1: 'rgba(30, 136, 229, 0.2)', topFillColor2: 'rgba(30, 136, 229, 0.2)',
						bottomLineColor: '#1e88e5', bottomFillColor1: 'rgba(30, 136, 229, 0.2)', bottomFillColor2: 'rgba(30, 136, 229, 0.2)',
						lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false,
					});
					const aboveBoxBottomLineNext = chart.addLineSeries({ color: '#1e88e5', lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false });
					const belowBoxBottomLineNext = chart.addLineSeries({ color: '#1e88e5', lineWidth: 1, lastValueVisible: false, priceLineVisible: false, crosshairMarkerVisible: false });

					let priceLines    = [];
					let monthlyLines  = [];
					let allLines      = [];
					let tomorrowLines = [];
					let dayAfterTomorrowLines = [];

					function clearLines(arr) {
						arr.forEach(pl => series.removePriceLine(pl));
						arr.length = 0;
					}
					let weeklyGammaLines = [];
					let monthlyGammaLines = [];

					function setStatus(text) { document.getElementById('status').textContent = text; }

					function toCandle(k) {
						return { time: Math.floor(k.t / 1000) + berlinOffset, open: parseFloat(k.o), high: parseFloat(k.h), low: parseFloat(k.l), close: parseFloat(k.c) };
					}

					const TF_WINDOW = { '1h': 30, '4h': 15, '1d': 365 };

					function applyVisibleRange() {
						const days = TF_WINDOW[INTERVAL] || 21;
						const now  = Math.floor(Date.now() / 1000) + berlinOffset;
						chart.timeScale().setVisibleRange({
							from: now - days * 86400,
							to:   now + days * 86400 * 0.03,
						});
					}

					async function loadCandles() {
						const resp = await (await fetch(klineUrl(INTERVAL, 500))).json();
						const klines = (resp.result || []).slice().reverse();
						series.setData(klines.map(toCandle));
						applyVisibleRange();
					}

					async function updateLatestCandle() {
						const resp = await (await fetch(klineUrl(INTERVAL, 2))).json();
						const klines = resp.result || [];
						if (!klines.length) return;
						series.update(toCandle(klines[0]));
					}

					async function setTf(iv) {
						INTERVAL = iv;
						document.querySelectorAll('.tf-btn').forEach(b => b.classList.toggle('active', b.textContent === iv));
						await loadCandles();
						await refreshQuadrantGamma();
						await refreshZonesExtrema();
						await refreshZonesBoxes();
						await refreshZonesBoxesNext();
					}

					async function refreshDeltaZero() {
						const data = await (await fetch(DZ_URL)).json();
						clearLines(priceLines);
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
						zeros.forEach(item => priceLines.push(series.createPriceLine({
							price: item.price, color: item.type === 'demand' ? 'red' : 'black', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, axisLabelColor: 'black', title: 'Weekly',
						})));
					}

					let nearestExpiryStr = null;
					let lastTradeCount = 0;

					function updateStatusLine() {
						const expiries = [INSTRUMENT, MONTHLY_INST].filter(Boolean).join('  ·  ');
						let text = expiries + '  ·  ' + lastTradeCount + ' trades';
						if (nearestExpiryStr) text += '  ·  Nearest: ' + nearestExpiryStr;
						setStatus(text);
					}

					async function refreshMonthlyDeltaZero() {
						if (!MDZ_URL) return;
						const data = await (await fetch(MDZ_URL)).json();
						clearLines(monthlyLines);
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
						zeros.forEach(item => monthlyLines.push(series.createPriceLine({
							price: item.price, color: item.type === 'demand' ? 'red' : 'black', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, axisLabelColor: 'black', title: 'Monthly',
						})));
						lastTradeCount = data.trade_count || 0;
						updateStatusLine();
					}

					async function refreshNearestExpiry() {
						// Cheap standalone lookup (no curve-building), shown regardless
						// of timeframe — unlike the yellow zones boxes (4h-only), which
						// use this same nearest-active-expiry internally.
						const data = await (await fetch(NEAREST_EXPIRY_URL)).json();
						nearestExpiryStr = data.expiry || null;
						updateStatusLine();
					}

					async function refreshAllDeltaZero() {
						const data = await (await fetch(ADZ_URL)).json();
						clearLines(allLines);
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a.price - b.price);
						zeros.forEach(item => allLines.push(series.createPriceLine({
							price: item.price, color: item.type === 'demand' ? 'red' : 'black', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, axisLabelColor: 'black', title: 'All',
						})));
					}

					async function refreshTomorrowDeltaZero() {
						const data = await (await fetch(DZT_URL)).json();
						clearLines(tomorrowLines);
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a - b);
						zeros.forEach(price => tomorrowLines.push(series.createPriceLine({
							price, color: 'black', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, axisLabelColor: 'black', title: 'Daily 24H',
						})));
					}

					async function refreshDayAfterTomorrowDeltaZero() {
						const data = await (await fetch(DZT2_URL)).json();
						clearLines(dayAfterTomorrowLines);
						const zeros = [...(data.delta_zero || [])].sort((a, b) => a - b);
						zeros.forEach(price => dayAfterTomorrowLines.push(series.createPriceLine({
							price, color: 'black', lineWidth: 1,
							lineStyle: LightweightCharts.LineStyle.Solid,
							axisLabelVisible: true, axisLabelColor: 'black', title: 'Daily+1 24H',
						})));
					}


					function drawGammaLines(data, lineStore, lineWidth, prefix, color = 'violet') {
						lineStore.forEach(l => series.removePriceLine(l));
						lineStore.length = 0;
						(data.peaks || []).forEach(item => {
							lineStore.push(series.createPriceLine({
								price: item.price, color, lineWidth,
								lineStyle: LightweightCharts.LineStyle.Solid,
								axisLabelVisible: true, axisLabelColor: 'black',
								title: prefix + ' ∧ ' + (item.delta_positive ? 'Long Call' : 'Long Put'),
							}));
						});
						(data.bottoms || []).forEach(item => {
							lineStore.push(series.createPriceLine({
								price: item.price, color, lineWidth,
								lineStyle: LightweightCharts.LineStyle.Solid,
								axisLabelVisible: true, axisLabelColor: 'black',
								title: prefix + ' ∨ ' + (item.delta_positive ? 'Short Put' : 'Short Call'),
							}));
						});
					}

					async function refreshWeeklyGamma() {
						const data = await (await fetch(GL_W_URL)).json();
						drawGammaLines(data, weeklyGammaLines, 2, 'Weekly', 'violet');
					}

					async function refreshMonthlyGamma() {
						if (!GL_M_URL) return;
						const data = await (await fetch(GL_M_URL)).json();
						drawGammaLines(data, monthlyGammaLines, 1, 'Monthly', 'violet');
					}

					async function refreshQuadrantGamma() {
						if (INTERVAL !== '1h') {
							netCallSeries.setData([]);
							netPutSeries.setData([]);
							return;
						}
						const data = await (await fetch(QG_URL)).json();
						const rows = data.quadrant_gamma || [];
						netCallSeries.setData(rows.map(r => ({ time: Math.floor(r.t / 1000) + berlinOffset, value: r.net_call_gamma })));
						netPutSeries.setData(rows.map(r => ({ time: Math.floor(r.t / 1000) + berlinOffset, value: r.net_put_gamma })));
					}

					async function refreshZonesExtrema() {
						if (INTERVAL !== '4h') {
							topIntersectionSeries.setData([]);
							bottomIntersectionSeries.setData([]);
							return;
						}
						const data = await (await fetch(ZE_URL)).json();
						const rows = data.zones_extrema || [];
						topIntersectionSeries.setData(rows.map(r => ({ time: Math.floor(r.t / 1000) + berlinOffset, value: r.top_intersection })));
						bottomIntersectionSeries.setData(rows.map(r => ({ time: Math.floor(r.t / 1000) + berlinOffset, value: r.bottom_intersection })));
					}

					function setBoxData(boxSeries, bottomLineSeries, top, bottom, fromTime, toTime) {
						// 0.0 is the "no crossing on this side" sentinel (see
						// dankbit.zones.extrema) — nothing real to draw.
						if (!top || !bottom) { boxSeries.setData([]); bottomLineSeries.setData([]); return; }
						boxSeries.applyOptions({ baseValue: { type: 'price', price: bottom } });
						boxSeries.setData([
							{ time: fromTime, value: top },
							{ time: toTime, value: top },
						]);
						bottomLineSeries.setData([
							{ time: fromTime, value: bottom },
							{ time: toTime, value: bottom },
						]);
					}

					function snapTo18(sec) {
						// Snap to 18:00 on the calendar day `sec` falls on — `sec` is
						// already Berlin-shifted (see berlinOffset), so treat it as UTC
						// when reading/writing calendar fields, consistent with the rest
						// of this file's time handling.
						const d = new Date(sec * 1000);
						return Math.floor(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate(), 18, 0, 0) / 1000);
					}

					async function refreshZonesBoxes() {
						if (INTERVAL !== '4h') {
							aboveBoxSeries.setData([]);
							belowBoxSeries.setData([]);
							aboveBoxBottomLine.setData([]);
							belowBoxBottomLine.setData([]);
							return;
						}
						// Live, non-persisted lookup — computed fresh by the server on
						// every call (see dankbit.zones.extrema.get_box), not read from
						// stored history.
						const data = await (await fetch(ZB_URL)).json();
						if (!data || data.t === undefined) {
							aboveBoxSeries.setData([]);
							belowBoxSeries.setData([]);
							aboveBoxBottomLine.setData([]);
							belowBoxBottomLine.setData([]);
							return;
						}
						const anchor = Math.floor(data.t / 1000) + berlinOffset;
						const fromTime = snapTo18(anchor - 2 * 86400);
						const toTime   = anchor;

						const aboveTop    = Math.max(data.short_zero_above_price, data.long_zero_above_price);
						const aboveBottom = Math.min(data.short_zero_above_price, data.long_zero_above_price);
						setBoxData(aboveBoxSeries, aboveBoxBottomLine, aboveTop, aboveBottom, fromTime, toTime);

						const belowTop    = Math.max(data.short_zero_below_price, data.long_zero_below_price);
						const belowBottom = Math.min(data.short_zero_below_price, data.long_zero_below_price);
						setBoxData(belowBoxSeries, belowBoxBottomLine, belowTop, belowBottom, fromTime, toTime);
					}

					async function refreshZonesBoxesNext() {
						if (INTERVAL !== '4h') {
							aboveBoxSeriesNext.setData([]);
							belowBoxSeriesNext.setData([]);
							aboveBoxBottomLineNext.setData([]);
							belowBoxBottomLineNext.setData([]);
							return;
						}
						// Same mechanism as refreshZonesBoxes(), sourced from the expiry
						// after the nearest one (see dankbit.zones.extrema.get_box_next).
						const data = await (await fetch(ZB_NEXT_URL)).json();
						if (!data || data.t === undefined) {
							aboveBoxSeriesNext.setData([]);
							belowBoxSeriesNext.setData([]);
							aboveBoxBottomLineNext.setData([]);
							belowBoxBottomLineNext.setData([]);
							return;
						}
						const anchor = Math.floor(data.t / 1000) + berlinOffset;
						const fromTime = snapTo18(anchor - 1 * 86400);
						const toTime   = anchor;

						const aboveTop    = Math.max(data.short_zero_above_price, data.long_zero_above_price);
						const aboveBottom = Math.min(data.short_zero_above_price, data.long_zero_above_price);
						setBoxData(aboveBoxSeriesNext, aboveBoxBottomLineNext, aboveTop, aboveBottom, fromTime, toTime);

						const belowTop    = Math.max(data.short_zero_below_price, data.long_zero_below_price);
						const belowBottom = Math.min(data.short_zero_below_price, data.long_zero_below_price);
						setBoxData(belowBoxSeriesNext, belowBoxBottomLineNext, belowTop, belowBottom, fromTime, toTime);
					}

					let rulerActive = false;
					let rulerPrice1 = null;
					let rulerLines  = [];

					function toggleRuler() {
						rulerActive = !rulerActive;
						document.getElementById('ruler-btn').classList.toggle('active', rulerActive);
						rulerLines.forEach(l => series.removePriceLine(l));
						rulerLines = [];
						rulerPrice1 = null;
						const info = document.getElementById('ruler-info');
						info.style.display = 'none';
						info.textContent = '';
					}

					chart.subscribeClick(param => {
						if (!rulerActive || !param.point) return;
						const price = series.coordinateToPrice(param.point.y);
						if (rulerPrice1 === null) {
							rulerPrice1 = price;
							rulerLines.push(series.createPriceLine({
								price, color: '#555', lineWidth: 1,
								lineStyle: LightweightCharts.LineStyle.Dashed,
								axisLabelVisible: true, axisLabelColor: 'black', title: '①',
							}));
						} else {
							rulerLines.push(series.createPriceLine({
								price, color: '#555', lineWidth: 1,
								lineStyle: LightweightCharts.LineStyle.Dashed,
								axisLabelVisible: true, axisLabelColor: 'black', title: '②',
							}));
							const pct = ((price - rulerPrice1) / rulerPrice1 * 100);
							const sign = pct >= 0 ? '+' : '';
							const info = document.getElementById('ruler-info');
							info.style.display = 'block';
							info.textContent = rulerPrice1.toFixed(0) + ' → ' + price.toFixed(0) + '   ' + sign + pct.toFixed(2) + '%';
							rulerPrice1 = null;
						}
					});

					async function init() {
						try { await loadCandles(); await refreshDeltaZero(); await refreshMonthlyDeltaZero(); await refreshAllDeltaZero(); await refreshTomorrowDeltaZero(); await refreshDayAfterTomorrowDeltaZero(); await refreshWeeklyGamma(); await refreshMonthlyGamma(); await refreshQuadrantGamma(); await refreshZonesExtrema(); await refreshZonesBoxes(); await refreshZonesBoxesNext(); await refreshNearestExpiry(); }
						catch (e) { setStatus('Error: ' + e.message); }
					}
					function saveChart() {
						const canvases = document.getElementById('chart-container').querySelectorAll('canvas');
						if (!canvases.length) return;
						const w = canvases[0].width, h = canvases[0].height;
						const out = document.createElement('canvas');
						out.width = w; out.height = h;
						const ctx = out.getContext('2d');
						ctx.fillStyle = '#ffffff';
						ctx.fillRect(0, 0, w, h);
						canvases.forEach(c => ctx.drawImage(c, 0, 0));
						const a = document.createElement('a');
						a.href = out.toDataURL('image/png');
						a.download = INSTRUMENT + '_delta_' + new Date().toISOString().slice(0,16).replace('T','_') + '.png';
						a.click();
					}

					init();
					setInterval(updateLatestCandle, 5000);
					setInterval(refreshDeltaZero, REFRESH);
					setInterval(refreshMonthlyDeltaZero, REFRESH);
					setInterval(refreshNearestExpiry, REFRESH);
					setInterval(refreshAllDeltaZero, REFRESH);
					setInterval(refreshTomorrowDeltaZero, REFRESH);
					setInterval(refreshDayAfterTomorrowDeltaZero, REFRESH);
					setInterval(refreshWeeklyGamma, REFRESH);
					setInterval(refreshMonthlyGamma, REFRESH);
					setInterval(refreshQuadrantGamma, REFRESH);
					setInterval(refreshZonesExtrema, REFRESH);
					setInterval(refreshZonesBoxes, REFRESH);
					setInterval(refreshZonesBoxesNext, REFRESH);
				//
